import React,{useState,useEffect} from "react"
import {graphql,Link }from 'gatsby'
import SEO from "../components/seo"
import {
  Container,
  Collapse,
  Navbar,
  NavbarToggler,
  Nav,
  NavItem,
} from "reactstrap"
import List from "../components/blog-list"

const SearchTemplate = ({ data }) => {
  const [isOpen, setIsOpen] = useState(false),toggle = () => setIsOpen(!isOpen);
    let { edges: posts } = data.allMarkdownRemark

  const [value, setValue] = useState('');

  const handleAddValue = (e) => {
    setValue(e.target.value);
  }
  var searchValue = value.trim().toLowerCase();

  if(searchValue.length > 0){
      var searchposts = posts.filter(l => {
        return l.node.frontmatter.title.toLowerCase().match( searchValue ) || l.node.html.toLowerCase().match(searchValue);
      });
  }

  useEffect(() => {
    var body = undefined;
    var menu = undefined;
    var menuItems = undefined;
    var toggleClass = function toggleClass(element, stringClass) {
      if (element.classList.contains(stringClass)) element.classList.remove(stringClass);else element.classList.add(stringClass);
    };

    var init = function init() {
      body = document.querySelector('body');
      menu = document.querySelector('.menu-icon');
      menuItems = document.querySelectorAll('.nav__list-item');
      menu.addEventListener('click', function () {
        console.log("masok")
        return toggleClass(body, 'nav-active');
      });
    };

    init();
  })

  return (
    <>
    <SEO title={value || "Search Page"} />
    
    <div class="nav">
      <div class="nav__content">
      <div class="container">
        <ul class="nav__list">
          <li class="nav__list-item active-nav"><Link className="hover-target" to="/">Home</Link></li>
          {/* <li class="nav__list-item"><Link className="hover-target" to="/blog">Blog</Link></li> */}
          <li class="nav__list-item"><a href="#" class="hover-target">About</a></li>
          <li class="nav__list-item"><Link className="hover-target" to="/search">Search</Link></li>
        </ul>
        </div>
      </div>
    </div>
            <Navbar className="navbar navbar-expand-lg navbar-light" id="mainNav" style={{ zIndex:'999'}}>
        <NavbarToggler onClick={toggle} />
        <Collapse isOpen={isOpen} navbar>
          <Nav className="ml-auto"navbar>
          <NavItem>
          <div class="nav-link menu-icon hover-target">
					<span class="menu-icon__line menu-icon__line-left"></span>
					<span class="menu-icon__line"></span>
					<span class="menu-icon__line menu-icon__line-right"></span>
				</div>	
          </NavItem>
          </Nav>
        </Collapse>
      </Navbar>
      <Container>
      <h1 className="display-1 mt-0" style={{ border:'unset'}}>
        <input type="text" value={value} onChange={handleAddValue} placeholder="Type here" autoFocus />
      </h1>
      <div className="blog-posts">
      {searchposts?
      (searchposts)
        .filter(post => post.node.frontmatter.title.length > 0)
        .map(({ node: post }) => {
          const { excerpt, id } = post
          const { title, path, date, tags } = post.frontmatter
          return (
              <List data={{ title, path, date, tags, excerpt, id }}/>
          )
        }):null
    }
    </div>
    </Container>
    </>
  )
}

export default SearchTemplate

export const searchListQuery = graphql`
  query BlogQuery {
    allMarkdownRemark(sort: { order: DESC, fields: [frontmatter___date] }) {
      edges {
        node {
          excerpt(pruneLength: 250)
          id
          html
          frontmatter {
            title
            date(formatString: "DD MMM YY")
            path
            tags
          }
        }
      }
    }
  }`